/// Fold (X != -1) & ((X + 1) <= Y) --> X < Y
/// When X != -1, the addition X+1 doesn't overflow, so we can simplify the comparison.
static Value *foldAddNoOverflowCheck(ICmpInst *Cmp0, ICmpInst *Cmp1, bool IsAnd,
                                     InstCombiner::BuilderTy &Builder) {
  if (!IsAnd)
    return nullptr;

  Value *Cmp0Op;
  const APInt *Cmp0C;
  ICmpInst::Predicate Cmp0Pred;

  Value *Cmp1Op;
  Value *Cmp1RHS;
  ICmpInst::Predicate Cmp1Pred;

  if (!match(Cmp0, m_ICmp(Cmp0Pred, m_Value(Cmp0Op), m_APInt(Cmp0C))))
    return nullptr;

  // We need: icmp ne X, -1
  if (Cmp0Pred != ICmpInst::ICMP_NE || !Cmp0C->isAllOnes())
    return nullptr;

  // We need: icmp ule (add X, 1), Y
  if (!match(Cmp1, m_ICmp(Cmp1Pred, m_Value(Cmp1Op), m_Value(Cmp1RHS))))
    return nullptr;

  if (Cmp1Pred != ICmpInst::ICMP_ULE)
    return nullptr;

  // Check if Cmp1Op is (add Cmp0Op, 1)
  const APInt *AddC;
  if (match(Cmp1Op, m_c_Add(m_Specific(Cmp0Op), m_APInt(AddC)))) {
    if (AddC->isOne()) {
      // (X != -1) & ((X + 1) <= Y) --> X < Y
      return Builder.CreateICmpULT(Cmp0Op, Cmp1RHS);
    }
  }

  return nullptr;
}

/// Fold (icmp)&(icmp) or (icmp)|(icmp) if possible.
/// If IsLogical is true, then the and/or is in select form and the transform
